27	struct DoseFormatted {
28	    
29	    let value: Float?
30	    let prefix: String
31	    let base: LocalizedStringResource
32	    let suffix: DoseDisplayMode.DoseRateSuffix?
33	
34	    var unitString: String {
35	        let baseStr = String(localized: base)
36	        let suffixStr = suffix.map { "/\(String(localized: $0.text))" } ?? ""
37	        return "\(prefix)\(baseStr)\(suffixStr)"
38	    }
39	    
40	    init(rawValue: Float?, unit: Settings.DoseMeasurementUnit, mode: DoseDisplayMode) {
41	        base = unit.title
42	        
43	        switch mode {
44	        case .dose:
45	            suffix = nil
46	        case .rate(let rate):
47	            suffix = rate
48	        }
49	
50	        guard let rawValue else {
51	            value = nil
52	            prefix = "μ"
53	            return
54	        }
55	
56	        let scaled = rawValue * (unit == .rem ? 100 : 1)
57	        if scaled >= 1_000_000 {
58	            value = scaled / 1_000_000
59	            prefix = ""
60	        } else if scaled >= 1_000 {
61	            value = scaled / 1_000
62	            prefix = "m"
63	        } else {
64	            value = scaled
65	            prefix = "μ"
66	        }
67	    }
68	}
